opencat.script:
ctx.fromTo(['panel-a','panel-b','panel-c'], {opacity:0, y:28, scale:0.96}, {opacity:1, y:0, scale:1, duration:0.7, stagger:0.12, ease:'spring.gentle'});
ctx.fromTo('kicker', {opacity:0, y:14}, {opacity:1, y:0, duration:0.55, ease:'ease-out'});
ctx.fromTo('title', {opacity:0, y:18}, {opacity:1, y:0, duration:0.7, delay:0.08, ease:'spring.gentle'});

ctx.to('headline', {
  duration: 2.2,
  delay: 0.35,
  scrambleText: {
    text: 'OPEN CAT RUNTIME',
    chars: 'upperCase',
    speed: 18,
    revealDelay: 0.08
  },
  ease: 'linear'
});

ctx.to('code-line', {
  duration: 2.4,
  delay: 0.75,
  scrambleText: {
    text: 'ctx.to("#title", { scrambleText: "READY" })',
    chars: '01{}[]<>/\\',
    speed: 26,
    revealDelay: 0.18
  },
  ease: 'linear'
});

ctx.to('status', {
  duration: 1.8,
  delay: 1.25,
  scrambleText: {
    text: 'LINK ESTABLISHED',
    chars: 'symbols',
    speed: 30,
    rightToLeft: true
  },
  ease: 'linear'
});

ctx.to('words', {
  duration: 2.0,
  delay: 1.7,
  scrambleText: {
    text: 'Render stable frames',
    delimiter: ' ',
    chars: 'lowerCase',
    tweenLength: true,
    speed: 12
  },
  ease: 'linear'
});

ctx.fromTo('scan', {x:-520, opacity:0.1}, {x:520, opacity:0.55, duration:2.1, delay:0.4, ease:'ease-in-out', repeat:1});
ctx.fromTo(['dot-a','dot-b','dot-c','dot-d','dot-e'], {opacity:0.2, scale:0.7}, {opacity:1, scale:1.2, duration:0.5, stagger:{each:0.18, from:'center'}, repeat:-1, yoyo:true, ease:'ease-in-out'});
